import{_ as d,o as r,c as a,a4 as e}from"./chunks/framework.BybBnFXO.js";const m=JSON.parse('{"title":"颜色成因","description":"","frontmatter":{"title":"颜色成因"},"headers":[],"relativePath":"zh/color-causes/intro.md","filePath":"zh/color-causes/intro.md","lastUpdated":1784176423000}'),o={name:"zh/color-causes/intro.md"};function n(s,t,i,l,h,c){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="颜色成因" tabindex="-1">颜色成因 <a class="header-anchor" href="#颜色成因" aria-label="Permalink to &quot;颜色成因&quot;">​</a></h1><p>珠宝的颜色并非孤立现象，而是由背后的物理化学机制决定。本分类模块介绍天然宝石中最重要的三种致色机制：</p><h2 id="三种主要机制" tabindex="-1">三种主要机制 <a class="header-anchor" href="#三种主要机制" aria-label="Permalink to &quot;三种主要机制&quot;">​</a></h2><table tabindex="0"><thead><tr><th>机制</th><th>概述</th></tr></thead><tbody><tr><td><a href="./transition-metal.html">过渡金属离子致色</a></td><td>过渡金属离子（如 Cr、Fe、Mn、Co、Ni、V、Cu、Ti）含有未填满的 d</td></tr><tr><td>或 f 电子层。当这些离子进入晶格取代主晶格中的位置（如 Al、Si、</td><td></td></tr><tr><td>Mg）时，其能级被晶场劈裂为多组 d-d 跃迁。吸收可见光特定波段后，</td><td></td></tr><tr><td>透射或反射光中残留的颜色即为我们看到的颜色。这是宝石界最重要</td><td></td></tr><tr><td>的致色机制，约 70% 的有色宝石属此类。</td><td></td></tr><tr><td></td><td></td></tr><tr><td><a href="./color-centers.html">色心致色</a></td><td>色心是晶格中能选择性吸收可见光的点缺陷。当晶格缺少某个离子</td></tr><tr><td>（空位）、多出一个离子（间隙），或含有杂质离子改变局部电荷平衡</td><td></td></tr><tr><td>时，邻近的电子或空穴被束缚在缺陷处形成&quot;色心&quot;，其能级刚好落在</td><td></td></tr><tr><td>可见光波段。色心可通过天然辐射或人工辐照（如加热后辐照）产生，</td><td></td></tr><tr><td>也可能因日晒褪色，这是检测优化处理的关键判断点。</td><td></td></tr><tr><td></td><td></td></tr><tr><td><a href="./charge-transfer.html">电荷转移</a></td><td>电荷转移是电子在相邻离子或同一离子的不同能级之间跳跃吸收光子</td></tr><tr><td>的过程。与 d-d 跃迁相比，电荷转移的吸收强度通常高 10²–10⁴ 倍，</td><td></td></tr><tr><td>因此即使致色离子浓度很低也能产生饱和浓艳的颜色。常见类型：</td><td></td></tr><tr><td><strong>金属-金属电荷转移（MMCT）</strong>、<strong>氧-金属电荷转移（OMCT）</strong>、</td><td></td></tr><tr><td><strong>金属-配体电荷转移（MLCT）</strong>。</td><td></td></tr><tr><td></td><td></td></tr></tbody></table><p><em>参见<a href="./../classification/intro.html">分类总览</a>了解矿物分类框架。</em></p>',5)])])}const f=d(o,[["render",n]]);export{m as __pageData,f as default};
